import{_ as i,o as a,c as e,a5 as l}from"./chunks/framework.B5tqjWbr.js";const k=JSON.parse('{"title":"项目 03：UPS C 固件骨架（UPS C Firmware Skeleton）","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"项目 03：UPS C 固件骨架（UPS C Firmware Skeleton）","tags":["power-electronics"],"status":"learning","summary":"把 `simulations/python/ups_mode_state_machine.py` 里的系统模式状态机迁移成一个可编译的简化 C 工程，帮助你阅读完整 UPS 工程代码时先抓住模块边界。"},"headers":[],"relativePath":"content/power/projects/03-ups-c-firmware-skeleton/README.md","filePath":"content/power/projects/03-ups-c-firmware-skeleton/README.md","lastUpdated":null}'),t={name:"content/power/projects/03-ups-c-firmware-skeleton/README.md"};function n(p,s,c,r,o,h){return a(),e("div",null,[...s[0]||(s[0]=[l(`<h1 id="项目-03-ups-c-固件骨架-ups-c-firmware-skeleton" tabindex="-1">项目 03：UPS C 固件骨架（UPS C Firmware Skeleton） <a class="header-anchor" href="#项目-03-ups-c-固件骨架-ups-c-firmware-skeleton" aria-label="Permalink to &quot;项目 03：UPS C 固件骨架（UPS C Firmware Skeleton）&quot;">​</a></h1><h2 id="目标" tabindex="-1">目标 <a class="header-anchor" href="#目标" aria-label="Permalink to &quot;目标&quot;">​</a></h2><p>把 <code>simulations/python/ups_mode_state_machine.py</code> 里的系统模式状态机迁移成一个可编译的简化 C 工程，帮助你阅读完整 UPS 工程代码时先抓住模块边界。</p><p>本项目不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据。所有输入序列和参数都是教学用的简化示例。</p><h2 id="学习重点" tabindex="-1">学习重点 <a class="header-anchor" href="#学习重点" aria-label="Permalink to &quot;学习重点&quot;">​</a></h2><ul><li>UPS 模式状态机（UPS mode state machine）如何串起在线模式、电池模式、旁路模式和故障模式。</li><li>控制中断服务程序（control interrupt service routine / control ISR）之外，系统级状态机如何决定输出许可。</li><li>脉宽调制（pulse-width modulation / PWM）许可、DC-DC 许可、PFC 许可和旁路模式（bypass mode）接触器许可如何由模式统一生成。</li><li>UPS C 参数表（UPS C parameter table）如何集中保存教学阈值、保持时间和控制周期，便于阅读和向导师提问。</li><li>UPS 保护标志（UPS protection flags）如何把采样值和参数表组合成欠压、过压、旁路不同步和停机请求。</li><li>保护去抖（protection debounce）和故障锁存（fault latch）如何把瞬时保护标志变成稳定故障状态。</li><li>系统故障闭环（system fault closure）如何把故障锁存接回模式状态机和输出许可。</li><li>故障码（fault code）和故障日志（fault log）如何记录故障发生时间、触发源、模式和锁存状态。</li><li>遥测（telemetry）通信帧如何把模式、故障码、时间戳和输出使能状态上报为外部可检查证据。</li><li>命令解析（command parsing）和安全门控（safety gating）如何把外部命令转换成内部意图，并阻止不安全的清故障请求。</li><li>命令响应（command response）如何用响应码和拒绝原因区分读状态成功、清故障被接受和清故障被拒绝。</li><li>参数访问（parameter access）如何区分只读、可读写和越界拒绝，避免通信写参数直接改 C 变量。</li><li>参数保存（parameter storage）如何用版本、有效标志和校验和判断 NVM 记录是否可信，并在失败时恢复默认值。</li><li>参数保存触发策略（parameter save scheduler）如何用脏标志、延时提交和最小保存间隔避免每次参数写入都立刻保存。</li></ul><h2 id="文件结构" tabindex="-1">文件结构 <a class="header-anchor" href="#文件结构" aria-label="Permalink to &quot;文件结构&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/ups_types.h             公共类型、模式、输入、输出和运行状态</span></span>
<span class="line"><span>src/inputs.c/.h             教学场景输入序列</span></span>
<span class="line"><span>src/mode_state_machine.c/.h UPS 模式状态机</span></span>
<span class="line"><span>src/outputs.c/.h            模式到执行器许可的映射</span></span>
<span class="line"><span>src/parameters.c/.h         教学参数表，不包含公司内部参数</span></span>
<span class="line"><span>src/protection.c/.h         教学保护判断，不包含公司内部保护阈值</span></span>
<span class="line"><span>src/fault_latch.c/.h        教学保护去抖和故障锁存，不包含公司内部故障策略</span></span>
<span class="line"><span>src/system_step.c/.h        教学系统仲裁，不包含公司内部系统仲裁策略</span></span>
<span class="line"><span>src/fault_log.c/.h          教学故障码和日志事件，不包含公司内部故障码</span></span>
<span class="line"><span>src/telemetry.c/.h          教学遥测通信帧，不包含公司内部通信协议</span></span>
<span class="line"><span>src/command_parser.c/.h     教学命令解析和安全门控，不包含公司内部通信命令</span></span>
<span class="line"><span>src/command_response.c/.h   教学命令响应和拒绝原因，不包含公司内部通信响应码</span></span>
<span class="line"><span>src/parameter_access.c/.h   教学参数访问边界，不包含公司内部参数访问表</span></span>
<span class="line"><span>src/parameter_storage.c/.h  教学参数保存和默认值恢复，不包含公司内部NVM格式</span></span>
<span class="line"><span>src/parameter_save_scheduler.c/.h 教学参数保存触发策略，不包含公司内部保存策略</span></span>
<span class="line"><span>src/main.c                  运行 9 个 tick 并打印证据</span></span></code></pre></div><h2 id="编译和运行" tabindex="-1">编译和运行 <a class="header-anchor" href="#编译和运行" aria-label="Permalink to &quot;编译和运行&quot;">​</a></h2><p>在 PowerShell 中：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cd E:\\gitee_CodeStorage\\学习\\电源</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gcc </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">std</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c99 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Wall </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Wextra </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Werror </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">I projects\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">03</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ups</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">firmware</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">skeleton\\src projects\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">03</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ups</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">firmware</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">skeleton\\src\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.c </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">o projects\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">03</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ups</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">firmware</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">skeleton\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ups_c_firmware_skeleton.exe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">projects\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">03</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ups</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">firmware</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">skeleton\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ups_c_firmware_skeleton.exe</span></span></code></pre></div><p>预期现象：</p><ul><li>程序先打印教学参数表：<code>mains_uv=180.0V</code>、<code>dc_bus_ov=420.0V</code>、<code>bypass_hold=30ms</code>、<code>isr=100us</code>。</li><li>程序随后打印教学保护标志：<code>mains_uv=1</code>、<code>dc_bus_ov=1</code>、<code>bypass_not_sync=1</code>、<code>shutdown=1</code>。</li><li>程序继续打印故障锁存演示：短毛刺不锁存、连续故障锁存、安全复位后清除。</li><li>程序继续打印系统故障闭环：锁存故障强制 <code>FAULT</code> 并关闭输出，安全复位后回到 <code>ONLINE</code>。</li><li>程序继续打印教学故障日志：时间戳、故障码、触发源、模式和锁存状态。</li><li>程序继续打印教学遥测通信帧：序号、时间戳、模式、故障码和四个输出使能状态。</li><li>程序继续打印教学命令解析：读状态请求产生遥测回复，不安全清故障被拦截，安全清故障被允许。</li><li>程序继续打印教学命令响应：读状态返回 <code>OK</code>，不安全清故障返回 <code>REJECTED / NOT_SAFE_TO_CLEAR</code>，安全清故障返回 <code>ACCEPTED</code>。</li><li>程序继续打印教学参数访问：可读写参数能读，写只读参数被拒绝，越界写入被拒绝，合法写入被接受。</li><li>程序继续打印教学参数保存：有效记录加载保存值，损坏记录校验失败后恢复默认值。</li><li>程序继续打印教学参数保存触发策略：0 ms 和 20 ms 两次写入被合并，80 ms 触发一次保存并清除脏标志。</li><li>tick 00：<code>ONLINE</code>，PFC 和逆变 PWM 允许。</li><li>tick 02：市电异常后进入 <code>BATTERY</code>，DC-DC 和逆变 PWM 允许。</li><li>tick 04：电池不可用且旁路同步后进入 <code>BYPASS</code>，旁路接触器允许，逆变 PWM 关闭。</li><li>tick 06：逆变器故障且旁路不可用后进入 <code>FAULT</code>，所有输出关闭并故障锁存。</li><li>tick 08：复位请求且市电恢复后回到 <code>ONLINE</code>。</li></ul><h2 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h2><ul><li>能指出 <code>UpsModeStateMachine_Step()</code> 的输入、状态和输出。</li><li>能解释为什么输出许可集中由 <code>UpsOutputs_FromMode()</code> 生成。</li><li>能解释为什么教学阈值集中由 <code>UpsParameters_GetDefault()</code> 返回。</li><li>能解释为什么保护判断集中由 <code>UpsProtection_Evaluate()</code> 产生标志。</li><li>能解释为什么故障锁存由 <code>UpsFaultLatch_Step()</code> 负责，而不是直接用瞬时故障标志停机。</li><li>能解释为什么系统仲裁由 <code>UpsSystem_Step()</code> 把故障锁存、模式状态机和输出许可串起来。</li><li>能解释为什么故障日志由 <code>UpsFaultLog_Record()</code> 记录故障码、时间戳、触发源和模式。</li><li>能解释为什么遥测通信帧由 <code>UpsTelemetry_BuildFrame()</code> 把内部状态转换成外部可观察证据。</li><li>能解释为什么命令解析由 <code>UpsCommand_Parse()</code> 产生内部意图，再由 <code>UpsCommand_ApplySafetyGate()</code> 决定清故障请求是否允许落地。</li><li>能解释为什么命令响应由 <code>UpsCommandResponse_FromCommand()</code> 把命令处理结果转换成外部可诊断的响应码和拒绝原因。</li><li>能解释为什么参数访问由 <code>UpsParameter_Read()</code> 和 <code>UpsParameter_Write()</code> 集中处理访问策略、范围校验和写入结果。</li><li>能解释为什么参数保存由 <code>UpsParameterStorage_Save()</code> 和 <code>UpsParameterStorage_LoadOrDefault()</code> 管理版本、有效标志、校验和和默认值恢复。</li><li>能解释为什么参数保存触发策略由 <code>UpsParameterSaveScheduler_ShouldSave()</code> 管理脏标志、延时提交和最小保存间隔。</li><li>能解释故障锁存为什么不能靠输入恢复自动清除。</li><li>能基于 <code>mode_state_machine.c -&gt; UpsModeStateMachine_Step()</code> 向导师询问真实工程的模块边界。</li><li>能基于 <code>parameters.c -&gt; UpsParameters_GetDefault()</code> 向导师询问真实工程的参数表组织方式，但不能记录公司内部参数。</li><li>能基于 <code>protection.c -&gt; UpsProtection_Evaluate()</code> 向导师询问真实工程中采样、参数和保护标志之间的边界。</li><li>能基于 <code>fault_latch.c -&gt; UpsFaultLatch_Step()</code> 向导师询问真实工程中保护去抖、锁存和复位条件的组织方式。</li><li>能基于 <code>system_step.c -&gt; UpsSystem_Step()</code> 向导师询问真实工程中故障闭环和输出许可仲裁的模块边界。</li><li>能基于 <code>fault_log.c -&gt; UpsFaultLog_Record()</code> 向导师询问真实工程中故障码、日志字段和持久化策略，但不能记录公司内部故障码。</li><li>能基于 <code>telemetry.c -&gt; UpsTelemetry_BuildFrame()</code> 向导师询问真实工程中通信上报字段、周期和故障上报入口，但不能记录公司内部通信协议。</li><li>能基于 <code>command_parser.c -&gt; UpsCommand_ApplySafetyGate()</code> 向导师询问真实工程中命令解析、安全门控和清故障条件的组织方式，但不能记录公司内部通信命令。</li><li>能基于 <code>command_response.c -&gt; UpsCommandResponse_FromCommand()</code> 向导师询问真实工程中响应码、拒绝原因和故障码之间的边界，但不能记录公司内部通信响应码。</li><li>能基于 <code>parameter_access.c -&gt; UpsParameter_Write()</code> 向导师询问真实工程中参数访问权限、范围校验和写入失败反馈方式，但不能记录公司内部参数访问表。</li><li>能基于 <code>parameter_storage.c -&gt; UpsParameterStorage_LoadOrDefault()</code> 向导师询问真实工程中参数保存、校验、默认值恢复和上报告警的组织方式，但不能记录公司内部NVM格式。</li><li>能基于 <code>parameter_save_scheduler.c -&gt; UpsParameterSaveScheduler_ShouldSave()</code> 向导师询问真实工程中参数保存触发、系统模式约束和掉电检测之间的边界，但不能记录公司内部保存策略。</li></ul>`,15)])])}const E=i(t,[["render",n]]);export{k as __pageData,E as default};
